INSERT INTO "public"."survey_questions" ("id", "survey_id", "project_id", "question_order", "question_text", "question_type", "category", "is_map_based", "allow_pin", "max_pins", "options", "max_selections", "sub_items", "scale_labels", "required", "created_at") VALUES ('10010a74-a82f-4bc1-9dc6-4b321696dc2a', 'a73aa716-b2d0-4b8b-a3e5-9123f6318008', 'X26-RB08', 13, 'Which types of new or improved spaces would most strengthen the connection between Lee College and the wider community? (Select your top 2)', 'multiple_choice', 'structured-survey', false, false, null, '["Public access to outdoor plazas or green spaces","Flexible event or performance venues","Shared spaces with community partners","Public-facing workforce training and demo facilities","An improved campus entry and gateway experience","Other"]', 2, null, null, true, '2026-04-07 21:51:42.394522+00'), ('16d84780-9ad7-439a-bbe3-d3d80e862464', 'a73aa716-b2d0-4b8b-a3e5-9123f6318008', 'X26-RB08', 20, 'Do you have any other comments or points you wish to make about the current or future condition of the Baytown Campus?', 'open_ended', 'structured-survey', false, false, null, null, null, null, null, false, '2026-04-07 21:51:42.394522+00'), ('1fd6c94a-d37b-4cc5-9a3e-7ef2bd7e833f', 'a73aa716-b2d0-4b8b-a3e5-9123f6318008', 'X26-RB08', 14, 'How strongly do you agree or disagree with the following statements?', 'matrix_likert', 'structured-survey', false, false, null, null, null, '["Lee College''s campus feels like an active part of the Baytown community","The campus is attractive and offers an appealing first impression.","The general appearance of the buildings represents the College well.","I would use outdoor classrooms and outdoor learning environments if they were available."]', '["Strongly Agree","Agree","Disagree","Strongly Disagree","No Opinion"]', true, '2026-04-07 21:51:42.394522+00'), ('32837f56-ae1a-41c3-88ee-91d2edc7a3b4', 'a73aa716-b2d0-4b8b-a3e5-9123f6318008', 'X26-RB08', 15, 'How strongly do you agree or disagree with the statements below about signage on the Baytown Campus?', 'matrix_likert', 'structured-survey', false, false, null, null, null, '["Signage is attractive, visible, illuminated, and appropriately located to allow easy navigation throughout campus.","Exterior building signage is easy to find and easy to read"]', '["Strongly Agree","Agree","Disagree","Strongly Disagree","No Opinion"]', true, '2026-04-07 21:51:42.394522+00'), ('4a3dfe81-eb02-4993-b224-5fdf443c7b31', 'a73aa716-b2d0-4b8b-a3e5-9123f6318008', 'X26-RB08', 2, 'Which campus location are you primarily affiliated with?', 'multiple_choice', 'about-you', false, false, null, '["Baytown Campus","McNair Center","Primarily Online"]', 1, null, null, true, '2026-04-07 21:51:42.394522+00'), ('5cc08b1c-36d0-4f3f-8531-0ef83a346703', 'a73aa716-b2d0-4b8b-a3e5-9123f6318008', 'X26-RB08', 3, 'How often do you physically come to the Baytown campus each week (on average)?', 'multiple_choice', 'about-you', false, false, null, '["5 or more days","3-4 days","1-2 days","I am primarily remote/online"]', 1, null, null, true, '2026-04-07 21:51:42.394522+00'), ('63092fe4-0cba-4184-9f51-2b3e22f86ace', 'a73aa716-b2d0-4b8b-a3e5-9123f6318008', 'X26-RB08', 5, 'What is your favorite photo-op location / "Instagram moment" on the Baytown campus? (Select your top two choices.)', 'open_ended', 'campus-experience', true, false, 2, null, null, null, null, true, '2026-04-07 21:51:42.394522+00'), ('668816cc-de81-431f-86c4-22ccabe16c23', 'a73aa716-b2d0-4b8b-a3e5-9123f6318008', 'X26-RB08', 17, 'How strongly do you agree or disagree with the statements below about pedestrian comfort and safety on the Baytown Campus?', 'matrix_likert', 'structured-survey', false, false, null, null, null, '["The campus is easy to navigate","I feel safe walking throughout campus","Buildings are well connected for walking between classes."]', '["Strongly Agree","Agree","Disagree","Strongly Disagree","No Opinion"]', true, '2026-04-07 21:51:42.394522+00'), ('6